import { initTRPC } from '@trpc/server';

/**
 * This is the context that will be available in all procedures
 */
export type Context = {
  userId: string;
};

/**
 * Initialize tRPC
 */
const t = initTRPC.context<Context>().create();

/**
 * Create a reusable router builder
 */
export const router = t.router;
export const publicProcedure = t.procedure;

import { router, publicProcedure } from './init';
import { z } from 'zod';

/**
 * Main tRPC router
 */
export const appRouter = router({
  /**
   * getUser procedure - returns the userId from the context
   * The context is created in the API route handler
   */
  getUser: publicProcedure.query(({ ctx }) => {
    return {
      userId: ctx.userId,
    };
  }),
});

/**
 * Export type of router for client-side usage
 */
export type AppRouter = typeof appRouter;

